def flatten(lst: list) -> list:
    flat_list = []
    for item in lst:
        # Check if the item is a list (but not a string, to avoid iterating characters)
        if isinstance(item, list):
            # Recursively call flatten and extend the result
            flat_list.extend(flatten(item))
        else:
            # Base case: the item is not a list, so append it
            flat_list.append(item)
    return flat_list

